#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        char c[6][10];
        for(int i=0;i<6;i++) scanf("%s",c[i]);
        int ok=0;
        // define indices of the eight corners
        int corners[8][3]={{0,2,4},{0,2,5},{0,3,4},{0,3,5},{1,2,4},{1,2,5},{1,3,4},{1,3,5}};
        for(int i=0;i<8 && !ok;i++){
            int a=corners[i][0], b=corners[i][1], d=corners[i][2];
            if(strcmp(c[a],c[b])==0 && strcmp(c[a],c[d])==0) ok=1;
        }
        puts(ok?"YES":"NO");
    }
    return 0;
}

